import{_ as a,a as l,b as r,c as i}from"./chunks/settings-about.vgbS8WoP.js";import{_ as o}from"./chunks/settings-add-model.Cxj4wiLe.js";import{_ as e,o as s,c as n,ag as d}from"./chunks/framework.BqfgOMAh.js";const A=JSON.parse('{"title":"设置说明","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/settings.md","filePath":"zh/guide/settings.md"}'),h={name:"zh/guide/settings.md"};function p(u,t,g,c,m,b){return s(),n("div",null,[...t[0]||(t[0]=[d('<h1 id="设置说明" tabindex="-1">设置说明 <a class="header-anchor" href="#设置说明" aria-label="Permalink to &quot;设置说明&quot;">​</a></h1><p>NexusFlow 的设置页面采用 iOS 风格的导航设计，集中管理 AI 模型、LLM 代理、Agent、快捷键、外观等配置。点击侧边栏顶部的齿轮图标即可进入设置。</p><h2 id="ai-模型" tabindex="-1">AI 模型 <a class="header-anchor" href="#ai-模型" aria-label="Permalink to &quot;AI 模型&quot;">​</a></h2><p>管理 AI 模型是使用 NexusFlow 的第一步。在这里你可以添加、验证和管理多个 AI 模型。</p><h3 id="模型列表" tabindex="-1">模型列表 <a class="header-anchor" href="#模型列表" aria-label="Permalink to &quot;模型列表&quot;">​</a></h3><p><img src="'+a+'" alt="AI 模型管理页面"></p><p>已添加的模型以卡片形式展示，每张卡片显示：</p><ul><li><strong>模型名称</strong>和 <strong>Provider 标签</strong></li><li><strong>验证状态</strong>：是否通过连接测试</li><li><strong>默认标记</strong>：标注当前使用的默认模型</li></ul><p>点击卡片可展开查看详细信息，包括模型标识、API Key（直接填写时掩码显示；环境变量引用时显示变量名）、Base URL、Temperature 和 Max Tokens。</p><h3 id="模型操作" tabindex="-1">模型操作 <a class="header-anchor" href="#模型操作" aria-label="Permalink to &quot;模型操作&quot;">​</a></h3><p>对每个已添加的模型，你可以：</p><ul><li><strong>验证模型</strong>：测试 API Key 和连接是否正常</li><li><strong>设为默认</strong>：将该模型设为 AI 对话使用的默认模型</li><li><strong>删除模型</strong>：移除不再需要的模型配置</li></ul><h3 id="添加新模型" tabindex="-1">添加新模型 <a class="header-anchor" href="#添加新模型" aria-label="Permalink to &quot;添加新模型&quot;">​</a></h3><p><img src="'+o+'" alt="添加 AI 模型表单"></p><p>点击「添加模型」按钮进入配置表单：</p><p><strong>1. 选择 Provider</strong></p><p>支持以下 AI 服务提供商：</p><table tabindex="0"><thead><tr><th>Provider</th><th>说明</th></tr></thead><tbody><tr><td>OpenAI</td><td>GPT 系列模型</td></tr><tr><td>Anthropic</td><td>Claude 系列模型</td></tr><tr><td>Google Gemini</td><td>Gemini 系列模型</td></tr><tr><td>DeepSeek</td><td>DeepSeek 系列模型</td></tr><tr><td>智谱 GLM</td><td>智谱 GLM 系列模型</td></tr><tr><td>MiniMax</td><td>MiniMax 系列模型</td></tr><tr><td>通义千问</td><td>通义千问 (Qwen) 系列模型</td></tr><tr><td>Kimi</td><td>Kimi 系列模型</td></tr><tr><td>Custom</td><td>自定义 API 地址</td></tr></tbody></table><p><strong>2. 填写基本信息</strong></p><ul><li><strong>模型名称</strong>（必填）：自定义名称，方便识别</li><li><strong>API Key</strong>（必填）：服务提供商的 API 密钥；也可以填写 <code>${OPENAI_API_KEY}</code> 这类环境变量引用，真实密钥由后端运行时读取，应用配置中只保存变量名引用</li><li><strong>模型标识</strong>（必填）：模型的具体型号，如 <code>gpt-5.4</code>、<code>claude-opus-4-6</code></li></ul><p><strong>3. 可选配置</strong></p><ul><li><strong>Temperature</strong>：控制回复的随机性，滑块范围 0 - 2，值越低回复越确定</li><li><strong>Max Tokens</strong>：AI 单次回复的最大 Token 数</li></ul><div class="tip custom-block"><p class="custom-block-title">Anthropic 协议注意</p><p>使用 Anthropic Messages API 协议时，Max Tokens 为<strong>必填项</strong>。</p></div><p><strong>4. Custom Provider 额外配置</strong></p><p>选择 Custom 时，需要额外填写：</p><ul><li><strong>API 地址</strong>：自定义 API 端点 URL</li><li><strong>通讯协议</strong>：选择与目标 API 兼容的协议 <ul><li>OpenAI Compatible</li><li>OpenAI Responses API</li><li>Anthropic Messages API</li><li>Google Gemini API</li></ul></li></ul><h2 id="llm-代理" tabindex="-1">LLM 代理 <a class="header-anchor" href="#llm-代理" aria-label="Permalink to &quot;LLM 代理&quot;">​</a></h2><p>LLM 代理是独立的全局设置，位于设置页的「LLM 代理」入口。它只影响 NexusFlow 桌面主程序发往 LLM 服务的请求，不影响 UE 插件、Rust Bridge、MCP Server、窗口通信等内部连接。</p><p>可配置项：</p><ul><li><strong>启用代理</strong>：开启或关闭全局 LLM 代理。</li><li><strong>协议</strong>：支持 HTTP、HTTPS、SOCKS4、SOCKS5。</li><li><strong>主机 / 端口</strong>：代理服务器地址，例如 <code>127.0.0.1:10808</code>。</li><li><strong>用户名 / 密码</strong>：可选认证信息；密码使用 NexusFlow 的加密密钥存储保存，不写入普通设置文件。</li><li><strong>测试代理连通性</strong>：只测试代理服务器地址和端口是否可连接，不验证目标 LLM 服务是否可访问。</li></ul><div class="warning custom-block"><p class="custom-block-title">代理规则提示</p><p>如果你的本地代理软件启用了「绕过大陆 IP」或类似分流规则，即使 NexusFlow 已经把 LLM 请求发送到本地代理，代理软件仍可能按目标服务器地理位置选择直连。需要强制走代理时，请在代理软件中关闭相应绕过规则或为目标 LLM 服务配置强制代理规则。</p></div><h2 id="agent-配置" tabindex="-1">Agent 配置 <a class="header-anchor" href="#agent-配置" aria-label="Permalink to &quot;Agent 配置&quot;">​</a></h2><p>配置 AI 助手的行为参数。</p><h3 id="最大迭代次数" tabindex="-1">最大迭代次数 <a class="header-anchor" href="#最大迭代次数" aria-label="Permalink to &quot;最大迭代次数&quot;">​</a></h3><p>设置 AI 在单次对话中的最大工具调用轮数，范围 1 - 1000。</p><ul><li><strong>默认值</strong>适合大多数场景</li><li>复杂的蓝图操作可能需要更多迭代次数</li><li>设置过低可能导致 AI 无法完成复杂任务</li></ul><h3 id="回复语言" tabindex="-1">回复语言 <a class="header-anchor" href="#回复语言" aria-label="Permalink to &quot;回复语言&quot;">​</a></h3><p>控制 AI 回复使用的语言，独立于界面显示语言：</p><ul><li><strong>跟随界面语言</strong>：使用与界面相同的语言</li><li><strong>简体中文</strong></li><li><strong>繁體中文</strong></li><li><strong>English</strong></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>你可以将界面设为英文，但让 AI 用中文回复，反之亦然。</p></div><h2 id="快捷键" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键" aria-label="Permalink to &quot;快捷键&quot;">​</a></h2><p><img src="'+l+'" alt="快捷键设置"></p><p>自定义 NexusFlow 的快捷键绑定。</p><h3 id="全局快捷键" tabindex="-1">全局快捷键 <a class="header-anchor" href="#全局快捷键" aria-label="Permalink to &quot;全局快捷键&quot;">​</a></h3><p>在任何应用中都可触发的快捷键：</p><ul><li><strong>切换侧边栏</strong>：自定义组合键，用于快速显示/隐藏 NexusFlow 侧边栏</li></ul><p>点击快捷键输入框后，直接按下想要的组合键即可录入。</p><h3 id="应用快捷键" tabindex="-1">应用快捷键 <a class="header-anchor" href="#应用快捷键" aria-label="Permalink to &quot;应用快捷键&quot;">​</a></h3><p>仅在 NexusFlow 窗口中生效的快捷键：</p><ul><li><strong>发送消息</strong>：选择 <strong>Enter</strong> 或 <strong>Ctrl+Enter</strong> 作为发送消息的快捷键 <ul><li>选择 <strong>Enter</strong>：按回车直接发送，Shift+Enter 换行</li><li>选择 <strong>Ctrl+Enter</strong>：按 Ctrl+Enter 发送，回车换行</li></ul></li></ul><h3 id="恢复默认" tabindex="-1">恢复默认 <a class="header-anchor" href="#恢复默认" aria-label="Permalink to &quot;恢复默认&quot;">​</a></h3><p>点击「恢复默认」按钮可将所有快捷键重置为默认值。</p><h2 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h2><p><img src="'+r+'" alt="外观设置"></p><p>个性化 NexusFlow 的视觉外观。</p><h3 id="主题" tabindex="-1">主题 <a class="header-anchor" href="#主题" aria-label="Permalink to &quot;主题&quot;">​</a></h3><p>三种主题模式：</p><ul><li><strong>深色</strong>（默认）：VS Code Dark 风格，护眼暗色主题</li><li><strong>浅色</strong>：明亮的浅色主题</li><li><strong>跟随系统</strong>：自动跟随 Windows 系统主题设置</li></ul><h3 id="语言" tabindex="-1">语言 <a class="header-anchor" href="#语言" aria-label="Permalink to &quot;语言&quot;">​</a></h3><p>界面显示语言：</p><ul><li><strong>跟随系统</strong>：自动跟随操作系统语言</li><li><strong>简体中文</strong></li><li><strong>繁體中文</strong></li><li><strong>English</strong></li></ul><h3 id="字体" tabindex="-1">字体 <a class="header-anchor" href="#字体" aria-label="Permalink to &quot;字体&quot;">​</a></h3><p>点击字体选择区域打开全屏字体选择器：</p><ul><li>列出系统已安装的所有字体</li><li>搜索框快速过滤</li><li>每个字体使用自身效果预览</li><li>点击即可选用</li></ul><h3 id="字号" tabindex="-1">字号 <a class="header-anchor" href="#字号" aria-label="Permalink to &quot;字号&quot;">​</a></h3><p>选择界面文字大小，提供 5 档选择：</p><ul><li>12px / 14px / <strong>16px</strong>（默认）/ 18px / 20px</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>外观设置修改后实时预览，自动保存，无需手动确认。</p></div><h2 id="关于" tabindex="-1">关于 <a class="header-anchor" href="#关于" aria-label="Permalink to &quot;关于&quot;">​</a></h2><p><img src="'+i+'" alt="关于页面"></p><p>查看应用信息和管理相关设置。</p><h3 id="应用信息" tabindex="-1">应用信息 <a class="header-anchor" href="#应用信息" aria-label="Permalink to &quot;应用信息&quot;">​</a></h3><ul><li><strong>版本号</strong>：当前 NexusFlow 版本</li><li><strong>Tauri 版本</strong>：底层框架版本</li></ul><h3 id="插件状态" tabindex="-1">插件状态 <a class="header-anchor" href="#插件状态" aria-label="Permalink to &quot;插件状态&quot;">​</a></h3><p>自动检测系统中的 Unreal Engine 安装，并检查 NexusFlow 插件是否已正确安装。</p><ul><li>显示检测到的 UE 版本</li><li>显示插件安装状态</li><li>点击「重新检测」刷新状态</li></ul><h3 id="匿名分析" tabindex="-1">匿名分析 <a class="header-anchor" href="#匿名分析" aria-label="Permalink to &quot;匿名分析&quot;">​</a></h3><p>可选的匿名使用数据收集，帮助改善产品。你可以随时开启或关闭此选项。</p><h3 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h3><p>提供以下外部链接（在系统浏览器中打开）：</p><ul><li>官方网站</li><li>使用文档</li><li>GitHub 仓库</li><li>问题反馈</li></ul><h3 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to &quot;许可证&quot;">​</a></h3><p>NexusFlow 采用 MIT License 开源许可证。点击可展开查看完整许可证文本。</p>',83)])])}const k=e(h,[["render",p]]);export{A as __pageData,k as default};
